          />

          <AdvantageGrid>
            {advantageItems.map((item) => (
              <FeatureCard key={item.title}>
                <div className="icon">{item.icon}</div>
                <h3>{item.title}</h3>
                <p>{item.text}</p>
              </FeatureCard>
